namespace sv_cc8bfe3ea367418384cbb7bc7bd08d93.Components;

public enum ScreenSize
{
    Mobile,
    Tablet,
    Desktop
}

export function getWidth() {
    return window.innerWidth;
}

export function addResizeListener(dotNetRef) {
    const handler = () => {
        dotNetRef.invokeMethodAsync("OnBrowserResize", window.innerWidth);
    };
    window.addEventListener("resize", handler);
    // Stash the handler so we can remove it later.
    window.__screenSizeHandler = handler;
}

export function removeResizeListener() {
    if (window.__screenSizeHandler) {
        window.removeEventListener("resize", window.__screenSizeHandler);
        delete window.__screenSizeHandler;
    }
}

@implements IAsyncDisposable
@inject IJSRuntime JS

<CascadingValue Value="currentSize">
    @ChildContent
</CascadingValue>

@code {
    [Parameter]
    public RenderFragment? ChildContent { get; set; }

    private ScreenSize currentSize = ScreenSize.Desktop;
    private IJSObjectReference? module;
    private DotNetObjectReference<ScreenSizeProvider>? dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        module = await JS.InvokeAsync<IJSObjectReference>(
            "import", "./js/screenSizeInterop.js");

        var width = await module.InvokeAsync<int>("getWidth");
        UpdateCategory(width);

        dotNetRef = DotNetObjectReference.Create(this);
        await module.InvokeVoidAsync("addResizeListener", dotNetRef);

        StateHasChanged();
    }

    [JSInvokable]
    public void OnBrowserResize(int width)
    {
        if (UpdateCategory(width))
        {
            StateHasChanged();
        }
    }

    private bool UpdateCategory(int width)
    {
        var newSize = width switch
        {
            < 768 => ScreenSize.Mobile,
            < 1024 => ScreenSize.Tablet,
            _ => ScreenSize.Desktop
        };

        if (newSize == currentSize) return false;
        currentSize = newSize;
        return true;
    }

    public async ValueTask DisposeAsync()
    {
        if (module is not null)
        {
            try
            {
                await module.InvokeVoidAsync("removeResizeListener");
                await module.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }

        dotNetRef?.Dispose();
    }
}

